/* FMVSS 600 Workshop — data payload. Loaded by fmvss-600-workshop.html before its inline script. */
window.FMVSS_DATA = {"scenarios": [{"id": "s1", "code": "Perception", "num": "01", "title": "Perception: Detecting People and Objects in Time to Stop", "short": "Perception", "assignment": "Your group's job is to draft a mock Federal Motor Vehicle Safety Standard that specifies how far away an automated vehicle must be able to detect and identify a pedestrian, so it can stop in time.", "prefix": "P"}, {"id": "s2", "code": "Minimal Risk Condition", "num": "02", "title": "Minimal Risk Condition: Reaching a Safe Stop After a Fault", "short": "Minimal Risk Condition", "assignment": "Your group's job is to draft a mock Federal Motor Vehicle Safety Standard that says how quickly and how safely an automated vehicle must reach a \u201cMinimal Risk Condition\u201d (a safe stop) after it detects a fault in its own systems.", "prefix": "M"}, {"id": "s3", "code": "Emergency Vehicle Detection", "num": "03", "title": "Emergency Vehicle Detection: Lights, Sirens, and Yielding", "short": "Emergency Vehicle Detection", "assignment": "Your group's job is to draft a mock Federal Motor Vehicle Safety Standard that says how an automated vehicle must detect an emergency vehicle (lights and/or siren) and how it must respond\u2014for example, pulling over and stopping.", "prefix": "E"}], "pieces": [{"id": "P1", "s": "s1", "title": "Closed-Course Detection Testing vs. Stopping Distance", "meta": ["Track testing report", "2025", "Independent vehicle test laboratory", "120 test runs, one production automated vehicle, dry pavement"], "defs": [["Detection distance", "How far away the vehicle's sensors first registered the pedestrian."], ["Stopping distance", "Reaction distance plus braking distance to a full stop."]], "chart": "P1", "caption": null, "table": null, "shows": "On a closed test track, engineers measured how far away the vehicle first detected an adult pedestrian test dummy at different speeds. The chart compares that with the distance the vehicle needs to come to a complete stop on a dry road. Detection distance stays roughly flat (the sensors have a fixed range), while stopping distance grows quickly with speed\u2014so the safety margin shrinks at higher speeds. Note the dashed line: in the worst 10% of runs, detection happened noticeably later."}, {"id": "P2", "s": "s1", "title": "Pedestrian Fatality Risk by Impact Speed", "meta": ["Crash database analysis", "2024", "University traffic-safety research center", "Analysis of 8,400 police-reported pedestrian crashes"], "defs": [["Impact speed", "The vehicle's speed at the moment it strikes the pedestrian."]], "chart": "P2", "caption": null, "table": null, "shows": "Researchers analyzed thousands of real pedestrian crashes and estimated the chance a pedestrian does not survive, based on the vehicle's speed at the moment of impact. Risk climbs steeply: a crash at 40 mph is roughly eight times deadlier than one at 20 mph. The takeaway for a standard: even when a vehicle cannot fully stop, detecting the pedestrian earlier and shedding more speed before impact saves lives, which may argue for a larger safety margin than the bare minimum."}, {"id": "P3", "s": "s1", "title": "Detection Range in Rain and Fog", "meta": ["University research study", "2025", "University engineering department", "40 instrumented test runs under controlled weather conditions"], "defs": [["Dense fog", "Visibility below roughly 500 feet in this study."]], "chart": "P3", "caption": null, "table": null, "shows": "The same vehicle and pedestrian target were tested in clear weather, rain, and fog. Detection range fell by more than half in heavy rain and by roughly 70% in dense fog. In dense fog, the vehicle could no longer detect the pedestrian far enough away to stop from 65 mph. A key question for your standard: does the requirement apply in clear weather only, in bad weather too, or should the vehicle be required to slow down when its sensors are degraded?"}, {"id": "P4", "s": "s1", "title": "Long-Range Sensor Product Sheet: \u201c985 ft Maximum Range\u201d", "meta": ["Supplier sensor spec sheet (marketing)", "2026", "Sensor manufacturer", "Manufacturer's own laboratory measurements"], "defs": [["Reflectivity", "The share of the sensor's light that a surface bounces back; brighter, more reflective objects are seen farther away."]], "chart": null, "caption": null, "table": {"headers": ["Specification", "Claimed Value"], "rows": [["Maximum detection range", "985 feet (300 meters)"], ["Field of view", "120 degrees horizontal"], ["Measurement rate", "20 full scans per second"], ["Operating temperature", "-40\u00b0F to +185\u00b0F"], ["Range condition (fine print)", "Measured on a stationary 3 ft \u00d7 3 ft panel with 90% reflectivity, in clear laboratory-equivalent conditions"]]}, "shows": "A sensor maker's product sheet advertises an impressive 985-foot maximum range. Read the fine print: that figure was measured on a large, highly reflective panel under ideal conditions. Typical pedestrian clothing reflects only about 5\u201310% of the sensor's light, and real roads involve rain, glare, and motion. Marketing specifications describe a component under best-case conditions; they are not evidence of whole-vehicle performance in the real world."}, {"id": "P5", "s": "s1", "title": "How Far Away Human Drivers First Glance at Pedestrians", "meta": ["Naturalistic driving study", "2023", "National transportation research institute", "Eye-tracking data from 3,400 volunteer drivers in everyday traffic"], "defs": [["Median", "The middle value\u2014half of drivers glanced earlier, half later."]], "chart": "P5", "caption": null, "table": null, "shows": "Using in-car cameras and eye-tracking, researchers measured how far away ordinary drivers first glanced toward a pedestrian near the road. Median distances ranged from about 180 feet at 25 mph to about 270 feet at 55 mph. Caution: a glance is not the same as reliable detection, and this study describes what human drivers happen to do, not what an automated system must do to be safe. Consider carefully whether \u201cas good as an average human\u201d is the right benchmark for a safety standard."}, {"id": "P6", "s": "s1", "title": "Standardized Pedestrian Test Target and Test Conditions", "meta": ["Draft industry test procedure", "2026", "Industry technical committee (draft)", "Consensus draft, not yet formally adopted"], "defs": [["Grip level (\u201cmu\u201d)", "A 0-to-1 measure of road grip; 0.8 is a normal dry road, wet roads are lower."]], "chart": null, "caption": null, "table": {"headers": ["Item", "Specification"], "rows": [["Adult pedestrian dummy", "5 ft 9 in tall, articulated legs, dressed in gray clothing"], ["Child pedestrian dummy", "3 ft 9 in tall, dressed in gray clothing"], ["Clothing reflectivity", "20\u201340% (typical of everyday clothing)"], ["Test surface", "Dry asphalt, grip level (\u201cmu\u201d) of 0.8 or higher"], ["Ambient conditions", "32\u00b0F to 100\u00b0F, no precipitation, daylight and darkness runs"], ["Position measurement", "Satellite-based positioning, accurate to within 4 inches"], ["Speed measurement", "Onboard data recorder, 100 readings per second"]]}, "shows": "A draft industry procedure describes exactly how a pedestrian-detection test could be run: what the test dummy looks like, what the road surface must be, and how distance and speed are measured. A good standard borrows this kind of detail so that any laboratory, anywhere, would get the same pass/fail answer. Your group can adopt, adapt, or tighten these specifications."}, {"id": "P7", "s": "s1", "title": "Adult vs. Child Pedestrian Targets: A Detection Gap", "meta": ["Track testing report", "2026", "Independent vehicle test laboratory", "80 test runs comparing adult and child pedestrian test dummies"], "defs": [["Child-size target", "A test dummy 3 ft 9 in tall, representing a young child near the roadway."]], "chart": "P7", "caption": "Distance needed to stop from 65 mph is approximately 250 ft.", "table": null, "shows": "A follow-up track test compared detection of an adult-size dummy against a child-size dummy. The child target was detected roughly 40% closer at every speed\u2014small targets simply return less sensor signal. At 65 mph, average child-detection distance (241 ft) falls short of the roughly 250 ft needed to stop. A standard that tests only adult targets could certify vehicles that cannot reliably protect children. Decide whether your standard requires testing with both."}, {"id": "P8", "s": "s1", "title": "National Poll: How Well Should a Self-Driving Car See?", "meta": ["Public opinion poll", "2026", "National polling organization", "Telephone and online survey of 2,000 adults, margin of error \u00b13%"], "defs": [["Margin of error", "The poll's built-in uncertainty; the true figure is likely within 3 points of the reported one."]], "chart": "P8", "caption": null, "table": null, "shows": "A national poll asked adults how a self-driving car's ability to spot pedestrians should compare to a human driver's. Nearly half said \u201cmuch farther than a human,\u201d and almost three-quarters wanted at least somewhat better than human performance. Caution: public opinion measures expectations and acceptability, not what is technically feasible or what level of performance is actually safe. A poll cannot supply a threshold, though it may inform how ambitious your standard should be."}, {"id": "M1", "s": "s2", "title": "Fault-Injection Track Testing: Measured Time to a Safe Stop", "meta": ["Track testing report", "2025", "Independent vehicle test laboratory", "60 trials on a closed course; faults deliberately triggered by a test harness"], "defs": [["Fault injection", "Deliberately causing a failure with test equipment to see how the vehicle responds."], ["Minimal Risk Condition (MRC)", "A condition to which a user or an ADS may bring a vehicle after performing the DDT fallback in order to reduce the risk of a crash when a given trip cannot or should not be completed."]], "chart": null, "caption": null, "table": {"headers": ["Fault Deliberately Triggered", "Severity", "What the Vehicle Did", "Average Time", "Slowest Run"], "rows": [["One of several cameras disabled", "Minor", "Continued to a parking area and stopped", "38 sec", "55 sec"], ["Main computer forced to switch to backup", "Major", "Pulled to the shoulder and stopped", "22 sec", "31 sec"], ["Steering assistance degraded", "Critical", "Stopped in its own lane, hazard lights on", "8 sec", "12 sec"]]}, "shows": "Engineers deliberately triggered faults and timed how long the vehicle took to reach a safe stop. More severe faults produced faster but less ideal stops (in-lane, rather than a shoulder or parking area). Timing was recorded by the onboard data recorder; the clock starts when the fault is triggered and stops when the vehicle is stationary with hazard lights on. This supports a tiered standard\u2014different time limits for different fault severities."}, {"id": "M2", "s": "s2", "title": "Simulated Crash Risk While Driving With a Fault", "meta": ["Computer simulation study", "2025", "University engineering department", "10 million simulated miles of driving with partly failed sensors"], "defs": [["Simulation", "A computer model of driving, not physical testing."]], "chart": "M2", "caption": null, "table": null, "shows": "In a large computer simulation, researchers estimated how crash risk grows the longer a vehicle keeps driving after part of its sensing has failed. Risk roughly doubles within the first minute and is more than ten times normal by five minutes. This argues for a tight time limit. But note: simulations depend on assumptions, and this one modeled a vehicle driving at full speed with no caution\u2014not one slowing down and looking for a safe place to stop."}, {"id": "M3", "s": "s2", "title": "Struck-From-Behind Events by Stop Location", "meta": ["Crash database analysis", "2024", "Insurance industry research group", "Records of 12,000 unplanned vehicle stops (all vehicle types, human and automated)"], "defs": [["Travel lane", "A lane with moving traffic, as opposed to a shoulder or parking area."]], "chart": "M3", "caption": null, "table": null, "shows": "When a vehicle stops unexpectedly, where it stops matters enormously. Vehicles stopped in a travel lane were struck from behind about 13 times more often than vehicles stopped on a shoulder. This is the tension at the heart of your standard: a rule that demands the fastest possible stop may push vehicles to stop in a live traffic lane\u2014trading one danger for another. Consider whether your standard should reward reaching a better stopping place, not just a faster stop."}, {"id": "M4", "s": "s2", "title": "Where Can a Vehicle Actually Pull Over? Shoulder Availability by Road Type", "meta": ["Roadway inventory analysis", "2023", "State transportation agency", "Measured road characteristics across a statewide road network"], "defs": [["Usable shoulder", "A paved area beside the travel lanes wide enough to fully fit a stopped vehicle."]], "chart": null, "caption": null, "table": {"headers": ["Road Type", "Miles with a Usable Shoulder", "Typical Speed"], "rows": [["Rural interstate highway", "92%", "65\u201375 mph"], ["Urban freeway", "61%", "55\u201365 mph"], ["Arterial (main city street)", "18%", "30\u201345 mph"], ["Downtown street", "4%", "25 mph or less"]]}, "shows": "A statewide road survey shows that a \u201cpull to the shoulder\u201d plan is realistic on rural highways but often impossible downtown, where only 4% of street miles have a usable shoulder. A single nationwide time limit may not fit every road. Your standard's test conditions could specify the road type(s) on which the requirement is tested\u2014or set different expectations for different environments."}, {"id": "M5", "s": "s2", "title": "Industry Survey: Self-Reported Time to a Safe Stop", "meta": ["Industry association survey (self-reported)", "2026", "Trade association of AV companies", "Written answers from 11 companies (Co. A through Co. K); 8 of 11 provided no supporting test data"], "defs": [["Self-reported", "The companies supplied their own numbers; nobody independently checked them."]], "chart": "M5", "caption": null, "table": null, "shows": "A trade association asked its member companies how quickly their vehicles can reach a safe stop. Claimed ranges vary enormously from 5 seconds to 2 minutes\u2014and most companies provided no test data to back up their answers. Self-reported figures from companies with a business interest in a lenient standard deserve caution. At most, this survey shows what industry says is feasible, not what is safe."}, {"id": "M6", "s": "s2", "title": "Simulator Study: How Fast Do Human Drivers Take Back Control?", "meta": ["Driving simulator study", "2023", "University human-factors laboratory", "96 licensed drivers in a driving simulator with surprise takeover alerts"], "defs": [["Takeover", "The moment a human resumes steering and braking from the automated system."]], "chart": "M6", "caption": null, "table": null, "shows": "In a driving simulator, researchers measured how long people took to retake control of a partially automated vehicle after an alert\u2014a median of about 6 seconds, with some drivers taking up to 25. Important caution: this study is about systems that hand control back to a human driver. The vehicles covered by your standard are designed to reach a safe stop on their own, with no human fallback. Decide whether this evidence belongs in your standard at all."}, {"id": "M7", "s": "s2", "title": "Field Data: How Long Real Safe-Stop Events Actually Took", "meta": ["Regulatory filing data (company-filed records)", "2024\u20132026", "Government reporting program", "1,240 real safe-stop events reported by operating AV fleets over 18 months"], "defs": [["Regulatory filing", "A report a company is legally required to submit to the government."]], "chart": "M7", "caption": null, "table": null, "shows": "Operating AV companies must file a report each time a vehicle performs an unplanned safe stop. Across 1,240 real events, about 7 in 10 vehicles were stopped within 30 seconds\u2014evidence that tight time limits are feasible in practice. But note the tail: 5% of events took more than 2 minutes, and the filings do not explain why. Also note who supplied the data: the companies themselves classify each event, and filings are not independently audited."}, {"id": "M8", "s": "s2", "title": "Investigation Report: A Fast Stop Is Not Always a Safe Stop", "meta": ["Government incident investigation report", "2025", "Independent safety investigation board", "In-depth investigation of three safe-stop incidents, including onboard data review"], "defs": [["Grade crossing", "A place where a road crosses railroad tracks at the same level."]], "chart": null, "caption": null, "table": {"headers": ["Incident", "Where the Vehicle Stopped", "Time to Stop", "Outcome"], "rows": [["Shuttle with sensor fault", "On a railroad grade crossing", "9 sec", "Near miss: crossing gates lowered with the shuttle inside them; occupants evacuated"], ["Robotaxi with computer fault", "In a crosswalk at a signalized intersection", "11 sec", "Blocked crossing pedestrians and cross traffic for 25 minutes until staff arrived"], ["Delivery vehicle with flat tire", "Traffic lane, crest of a hill", "7 sec", "Struck from behind by a following vehicle with limited sight distance; minor injuries"]]}, "shows": "Investigators examined three incidents in which vehicles stopped quickly after a fault and created a new hazard by stopping in exactly the wrong place: a rail crossing, a crosswalk, a blind hillcrest. Each vehicle technically reached a \u201csafe stop\u201d well inside any plausible time limit. The lesson for your standard: consider prohibiting certain stop locations, or requiring the vehicle to keep moving briefly when stopping immediately would be more dangerous."}, {"id": "E1", "s": "s3", "title": "Closed-Course Test: Response to an Approaching Ambulance", "meta": ["Track testing report", "2025", "Independent vehicle test laboratory", "50 test runs; a real ambulance approached from behind with lights and siren active"], "defs": [["Yield", "Move out of the emergency vehicle's path and stop, as the law requires of human drivers."]], "chart": null, "caption": null, "table": {"headers": ["Measurement", "Result"], "rows": [["Distance at which the vehicle first detected the ambulance", "Average 420 ft (worst run: 180 ft)"], ["Time from detection to beginning to pull over", "Average 3.2 sec (worst run: 6.8 sec)"], ["Runs where the vehicle fully yielded before the ambulance arrived", "46 out of 50"], ["Runs where the ambulance had to change lanes around the vehicle", "4 out of 50"]]}, "shows": "On a closed course, an ambulance with lights and siren repeatedly approached an automated vehicle from behind. The vehicle usually detected it around 420 feet away and began pulling over within about 3 seconds\u2014but in 4 of 50 runs it failed to yield in time. A standard could set minimums for each of these measurements: detection distance, response time, and success rate. Ask yourselves: is 46 out of 50 good enough for a federal standard?"}, {"id": "E2", "s": "s3", "title": "How Far Away Can a Siren Be Heard at Speed?", "meta": ["Acoustic field study", "2024", "National standards laboratory", "Calibrated microphone measurements inside a moving vehicle, 5 speeds \u00d7 20 runs"], "defs": [["Detectable", "The siren stood out clearly above the background noise on a calibrated recording."]], "chart": "E2", "caption": "At 65 mph, a siren detected at ~200 ft gives only about 2 seconds of warning.", "table": null, "shows": "Wind and road noise rise with speed, drowning out sirens. At 25 mph a siren was detectable about 900 feet away; at 65 mph, only about 200 feet\u2014roughly 2 seconds of warning for a fast-closing ambulance. The implication: a standard that relies on sound alone will fail at highway speeds. Consider requiring the vehicle to detect emergency lights visually as well, and at a greater distance."}, {"id": "E3", "s": "s3", "title": "Standardized \u201cSurrogate\u201d Emergency Vehicle for Testing", "meta": ["Draft industry test procedure", "2026", "Industry technical committee (draft)", "Consensus draft, not yet formally adopted"], "defs": [["Surrogate", "A stand-in test device that mimics a real emergency vehicle."], ["Decibel", "A standard unit of loudness; 110 decibels is about as loud as a rock concert."]], "chart": null, "caption": null, "table": {"headers": ["Item", "Specification"], "rows": [["Light bar flash rate", "60 to 240 flashes per minute"], ["Light intensity", "At least 700 candela per flash head (candela: a standard unit of light brightness; one candle is about 1 candela)"], ["Light colors", "Red and blue, plus white flashers"], ["Siren playback", "Recorded siren, calibrated to 110 decibels measured 10 feet away"], ["Approach scenarios", "From behind (same lane and adjacent lane) and crossing at an intersection"], ["What gets recorded", "Video of the vehicle's behavior plus its onboard data log"]]}, "shows": "Testing with real ambulances is expensive and hard to repeat exactly. This draft procedure defines a standardized \u201csurrogate\u201d\u2014a test rig with calibrated lights and a recorded siren\u2014so every test lab presents the vehicle with exactly the same stimulus. Your standard can reference a surrogate like this in its test procedure to make pass/fail results repeatable."}, {"id": "E4", "s": "s3", "title": "Voluntary Incident Reports: Where Problems Actually Occur", "meta": ["Public incident report database", "2023\u20132025", "Government incident reporting program", "87 voluntary reports filed by emergency responders and the public"], "defs": [["Voluntary reporting", "People choose whether to file a report, so many events go unreported."]], "chart": "E4", "caption": null, "table": null, "shows": "A public database collects reports of problem encounters between automated vehicles and emergency responders. The most common report is failing to pull over for an approaching emergency vehicle, but a third of reports involve a different problem: stopping too close to responders already working on the shoulder, or blocking scenes and station driveways. Limitations: reporting is voluntary, so these 87 reports are not a complete count\u2014but the pattern suggests a standard covering only the \u201cpull over\u201d scenario would miss real problems."}, {"id": "E5", "s": "s3", "title": "\u201c12 Shocking Robot Car Failures\u201d \u2014 Advocacy Video Compilation", "meta": ["Advocacy group compilation (social media)", "2026", "Advocacy organization", "12 viral video clips collected from social media; sources unverified"], "defs": [["Denominator", "The total number of opportunities for something to happen\u2014without it, a count of failures cannot tell you how often failure occurs."]], "chart": null, "caption": null, "table": {"headers": ["Clip", "What the Video Appears to Show", "Verified?"], "rows": [["Clips 1\u20135", "Automated vehicles not yielding to emergency vehicles", "No \u2014 locations and dates unconfirmed"], ["Clips 6\u20138", "Vehicles stopped in front of fire trucks", "No \u2014 2 of 3 later shown to involve human-driven vehicles"], ["Clips 9\u201312", "Assorted traffic confusion near emergency scenes", "No \u2014 vehicle type and cause unclear in the footage"]]}, "shows": "An advocacy group's viral video compiles 12 dramatic clips of \u201crobot car failures\u201d around emergency vehicles. The clips are emotionally powerful, but there is no denominator (12 clips out of how many millions of miles?), sources are unverified, and at least two clips turned out to involve ordinary human-driven cars. Compelling footage is not the same as reliable evidence\u2014though it may still tell you what the public is worried about."}, {"id": "E6", "s": "s3", "title": "Emergency Lights and Sirens Vary by State", "meta": ["Legal and regulatory survey", "2024", "National association of state officials", "Review of emergency-vehicle equipment laws in all 50 states"], "defs": [["Courtesy light", "A small flashing light used by volunteer responders in their personal vehicles."]], "chart": null, "caption": null, "table": {"headers": ["Feature", "How It Varies Across States"], "rows": [["Blue lights", "Police only in some states; fire and EMS may also use blue in others"], ["Green lights", "Used by volunteer responders or command vehicles in some states; not permitted in others"], ["Volunteer firefighter vehicles", "Many states allow personal vehicles with a single dashboard \u201ccourtesy light\u201d responding to calls"], ["Siren tones", "Wail, yelp, and \u201chi-lo\u201d tones all in use; some tones reserved for specific uses in some states"]]}, "shows": "What counts as an \u201cemergency vehicle\u201d is not uniform: light colors, siren tones, and volunteer responder equipment differ from state to state. A vehicle tested only against a big-city ambulance might miss a volunteer firefighter's pickup with a dashboard light. Your standard's test procedure must decide what range of lights and sirens the vehicle is required to recognize."}, {"id": "E7", "s": "s3", "title": "Seeing Emergency Lights: Lighting Conditions Change Everything", "meta": ["Acoustic and optical field study", "2025", "National standards laboratory", "Instrumented camera measurements of a standard light bar, 4 lighting conditions \u00d7 15 runs"], "defs": [["Sun glare", "The sun low in the sky, shining toward the vehicle's cameras."]], "chart": "E7", "caption": null, "table": null, "shows": "The same flashing light bar was measured under four lighting conditions. At night it was visually detectable more than 2,600 feet away; in bright sun glare, only about 420 feet\u2014an 84% reduction. Combined with the siren study (E2), this shows that neither lights nor sirens work at all distances in all conditions. Your test conditions should specify the lighting environments in which the vehicle must pass\u2014a vehicle tested only at night would face its easiest case."}, {"id": "E8", "s": "s3", "title": "Observational Study: How Often Do Human Drivers Yield Properly?", "meta": ["Roadside observational study", "2023", "University traffic-safety research center", "1,800 observed encounters between human-driven vehicles and emergency vehicles"], "defs": [["Observational study", "Researchers watched real traffic without interfering; nothing was staged."]], "chart": "E8", "caption": null, "table": null, "shows": "Researchers stationed observers along emergency response routes and recorded how human drivers actually behaved: only about two-thirds yielded fully and promptly, and nearly 1 in 10 failed to yield at all. Some argue an automated vehicle need only beat this imperfect human baseline; others argue a federal standard should demand near-perfect compliance from a machine. This study describes what humans do; it does not tell you what the standard should require. Use it to frame that debate, not to settle it."}], "characteristics": [["Performance-based", "It says what the vehicle must do, not how it must be built. (Never require a specific brand or type of sensor.)"], ["Objective pass/fail", "It draws a measurable line using numbers and units (feet, seconds, success rate), so pass or fail is not a judgment call."], ["Defined test conditions", "It says exactly when and where the test applies: weather, road surface, speeds, lighting."], ["Prescribed instrumentation", "It says what standardized equipment runs and measures the test (test dummies, surrogate devices, data recorders)."]], "charts": {"P1": "data:image/png;base64,", "P2": "data:image/png;base64,", "P3": "data:image/png;base64,", "P5": "data:image/png;base64,", "P7": "data:image/png;base64,", "P8": "data:image/png;base64,", "M2": "data:image/png;base64,", "M3": "data:image/png;base64,", "M5": "data:image/png;base64,", "M6": "data:image/png;base64,", "M7": "data:image/png;base64,", "E2": "data:image/png;base64,", "E4": "data:image/png;base64,", "E7": "data:image/png;base64,", "E8": "data:image/png;base64,"}};
